SELECT COUNT(1)
FROM sys_role
WHERE role_code = #{roleCode}
  AND deleted = 0

      AND id != #{excludeId}

SELECT FROM sys_role WHERE deleted = 0
AND (role_code LIKE CONCAT('%', #{keyword}, '%') OR role_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY sort ASC, id DESC LIMIT #{size} OFFSET #{offset}
